allow:
Read(//^format:/ { in_format=1; next }
  in_format && /^[[:space:]]+html:[[:space:]]*$/ {
    getline nextline
    if \(nextline ~ /^[[:space:]]*$/ || nextline ~ /^---/ || nextline ~ /^[a-zA-Z]/ || nextline ~ /^#/\) {
      print FILENAME
      exit
    }
  }
  in_format && /^[^[:space:]]/**)
